import {
  DURATION,
  DURATION_DESCRIPTIONS,
  SEMANTIC_DURATION,
  SEMANTIC_DURATION_DESCRIPTIONS,
} from './tokens.js';

export default {
  title: 'Motion/Duration',
  parameters: {
    layout: 'fullscreen',
    docs: {
      description: {
        component:
          'Primitive duration scale (8 steps) and semantic aliases (5 named intents). ' +
          'Click any row to trigger the animation. All boxes slide 120px to the right.',
      },
    },
  },
};

// ---------------------------------------------------------------------------
// Shared styles
// ---------------------------------------------------------------------------
const baseStyles = `
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f8f8f8; }

  .page { max-width: 860px; margin: 0 auto; padding: 48px 32px; }
  .page-title { font-size: 13px; font-weight: 600; color: #666; text-transform: uppercase; letter-spacing: 0.08em; margin-bottom: 4px; }
  .page-subtitle { font-size: 20px; font-weight: 700; color: #111; margin-bottom: 8px; }
  .page-description { font-size: 14px; color: #555; line-height: 1.5; margin-bottom: 40px; }

  .section-label { font-size: 11px; font-weight: 600; color: #999; text-transform: uppercase; letter-spacing: 0.1em; margin-bottom: 12px; padding-bottom: 8px; border-bottom: 1px solid #e4e4e4; }

  .row {
    display: grid;
    grid-template-columns: 180px 80px 1fr 60px;
    align-items: center;
    gap: 16px;
    padding: 14px 0;
    border-bottom: 1px solid #f0f0f0;
    cursor: pointer;
  }
  .row:hover { background: #fafafa; margin: 0 -16px; padding-left: 16px; padding-right: 16px; }
  .row:last-child { border-bottom: none; }

  .token-name { font-size: 13px; font-family: 'SF Mono', 'Fira Code', monospace; color: #333; }
  .token-alias { font-size: 11px; color: #888; margin-top: 2px; }
  .token-value { font-size: 13px; font-weight: 600; color: #0066cc; font-family: monospace; }
  .token-desc { font-size: 12px; color: #777; line-height: 1.4; }

  .stage { width: 200px; height: 44px; background: #f0f0f0; border-radius: 6px; overflow: hidden; position: relative; }
  .box {
    width: 44px; height: 44px;
    background: #333;
    border-radius: 5px;
    display: flex; align-items: center; justify-content: center;
    position: absolute; left: 0; top: 0;
    cursor: pointer;
  }
  .box-label { font-size: 9px; color: #fff; font-weight: 600; text-align: center; line-height: 1.2; }

  .header-row {
    display: grid;
    grid-template-columns: 180px 80px 1fr 60px;
    gap: 16px;
    padding: 0 0 8px 0;
    font-size: 11px;
    font-weight: 600;
    color: #aaa;
    text-transform: uppercase;
    letter-spacing: 0.08em;
  }

  .section { margin-bottom: 48px; }
`;

// ---------------------------------------------------------------------------
// Render helper
// ---------------------------------------------------------------------------
function buildRow(tokenName, valuems, description, alias = null) {
  const ms = parseInt(valuems, 10);
  const safeId = tokenName.replace(/[^a-z0-9]/gi, '_');

  return `
    <div class="row" data-dur="${ms}" data-id="${safeId}" onclick="triggerAnimation('${safeId}', ${ms})">
      <div>
        <div class="token-name">${tokenName}</div>
        ${alias ? `<div class="token-alias">→ ${alias}</div>` : ''}
      </div>
      <div class="token-value">${valuems}</div>
      <div class="token-desc">${description}</div>
      <div class="stage">
        <div class="box" id="box_${safeId}">
          <div class="box-label">${ms}ms</div>
        </div>
      </div>
    </div>
  `;
}

// ---------------------------------------------------------------------------
// Story: Primitives
// ---------------------------------------------------------------------------
export const Primitives = {
  name: 'Primitive durations',
  render: () => {
    const rows = Object.entries(DURATION)
      .map(([key, val]) =>
        buildRow(`duration.${key}`, val, DURATION_DESCRIPTIONS[key] || '')
      )
      .join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>${baseStyles}</style>
      <div class="page">
        <div class="page-title">Motion / Duration</div>
        <div class="page-subtitle">Primitive durations</div>
        <div class="page-description">
          Eight raw duration steps — brand-variable values with no semantic meaning.
          Click any row to trigger the slide animation using that duration.
        </div>
        <div class="section">
          <div class="header-row">
            <div>Token</div>
            <div>Value</div>
            <div>Description</div>
            <div>Preview</div>
          </div>
          ${rows}
        </div>
      </div>
    `;

    el.querySelectorAll('.box').forEach((box) => {
      box.style.transform = 'translateX(0px)';
    });

    // Attach animation function
    el.ownerDocument.defaultView.triggerAnimation = (id, durationMs) => {
      const box = el.querySelector(`#box_${id}`);
      if (!box || box._animating) return;
      box._animating = true;
      box.animate(
        [
          { transform: 'translateX(0px)' },
          { transform: 'translateX(156px)' },
          { transform: 'translateX(0px)' },
        ],
        {
          duration: durationMs * 2,
          easing: 'cubic-bezier(0.4, 0, 0.2, 1)',
          fill: 'forwards',
        }
      ).onfinish = () => {
        box._animating = false;
      };
    };

    return el;
  },
};

// ---------------------------------------------------------------------------
// Story: Semantics
// ---------------------------------------------------------------------------
export const Semantics = {
  name: 'Semantic aliases',
  render: () => {
    const rows = Object.entries(SEMANTIC_DURATION)
      .map(([name, val]) => {
        // Find the primitive key this maps to
        const primKey = Object.entries(DURATION).find(([, v]) => v === val)?.[0];
        const alias = primKey ? `duration.${primKey}` : '';
        return buildRow(
          `motion.duration.${name}`,
          val,
          SEMANTIC_DURATION_DESCRIPTIONS[name] || '',
          alias
        );
      })
      .join('');

    const el = document.createElement('div');
    el.innerHTML = `
      <style>${baseStyles}</style>
      <div class="page">
        <div class="page-title">Motion / Duration</div>
        <div class="page-subtitle">Semantic duration aliases</div>
        <div class="page-description">
          Five named intents that reference primitive durations. The alias column shows
          which primitive is referenced. Click any row to preview.
        </div>
        <div class="section">
          <div class="header-row">
            <div>Token</div>
            <div>Value</div>
            <div>Intent</div>
            <div>Preview</div>
          </div>
          ${rows}
        </div>
      </div>
    `;

    el.ownerDocument.defaultView.triggerAnimation = (id, durationMs) => {
      const box = el.querySelector(`#box_${id}`);
      if (!box || box._animating) return;
      box._animating = true;
      box.animate(
        [
          { transform: 'translateX(0px)' },
          { transform: 'translateX(156px)' },
          { transform: 'translateX(0px)' },
        ],
        {
          duration: durationMs * 2,
          easing: 'cubic-bezier(0.4, 0, 0.2, 1)',
          fill: 'forwards',
        }
      ).onfinish = () => {
        box._animating = false;
      };
    };

    return el;
  },
};
